struct Info {
	Info() :tmp() {};
	void push_back(int x) {
		tmp.pb(x);
	}
	int size() const {
		return tmp.size();
	}
	vector<int> tmp;
};

Info operator+(const Info& lower, const Info& upper) {
	Info res;
	var& tmp = res.tmp;
	int mn = min(10, lower.size() + upper.size());
	int i = 0, j = 0;
	while (tmp.size() != mn) {
		if (i <= vs(lower) and j <= vs(upper)) {
			if (lower.tmp[i] < upper.tmp[j]) {
				tmp.pb(lower.tmp[i]);
				i++;
			}
			else {
				tmp.pb(upper.tmp[j]);
				j++;
			}
		}
		else if (i <= vs(lower)) {
			tmp.pb(lower.tmp[i]);
			i++;
		}
		else {
			tmp.pb(upper.tmp[j]);
			j++;
		}
	}
	return res;
}

void solve(int CASE)
{
	int n, m, q; cin >> n >> m >> q;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var dep = vector<int>(n + 2);
	var p = Vec2<int>(n + 1, 21);
	var dfs = [&](var dfs, int now, int fa)->void {
		dep[now] = dep[fa] + 1;
		p[now][0] = fa;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
		}
		};
	dfs(dfs, 1, 0);

	var lca = [&dep, &p](int x, int y)->int {
		if (dep[x] < dep[y])swap(x, y);
		for (int i = 20; i >= 0; i--)
			if (dep[x] - (1 << i) >= dep[y])
				x = p[x][i];
		if (x == y) return x;
		for (int i = 20; i >= 0; i--)
			if (p[x][i] != p[y][i])
				x = p[x][i], y = p[y][i];
		return p[x][0];
		};

	var dp = Vec2<Info>(n + 1, 21);
	fa(i, 1, m) {
		int x; cin >> x;
		dp[x][0].pb(i);
	}
	fa(j, 1, 20) {
		fa(i, 1, n) {
			p[i][j] = p[p[i][j - 1]][j - 1];
			dp[i][j] = dp[i][j - 1] + dp[p[i][j - 1]][j - 1];
		}
	}
	var jump = [&](int now, int cha)->Info {
		Info res;
		fa(i, 0, 20)if (cha & (1 << i)) {
			res = res + dp[now][i];
			now = p[now][i];
		}
		return res;
		};

	while (q--) {
		int u, v, a; cin >> u >> v >> a;
		int l = lca(u, v);

		Info res;
		if (l == v)res = jump(u, dep[u] - dep[l] + 1);
		else if (l == u)res = jump(v, dep[v] - dep[l] + 1);
		else res = jump(u, dep[u] - dep[l] + 1) + jump(v, dep[v] - dep[l]);

		int siz = min(a, (int)res.tmp.size());
		cout << siz << ' ';
		fa(i, 0, siz - 1)cout << res.tmp[i] << ' ';
		cout << endl;
	}
	return;
}
